mapper.select:
SELECT id, project_id, file_path, language, chunk_type,
start_line, end_line, content, summary, metadata, keywords,
1 - (embedding <=> #{queryVector}::vector) AS score
FROM code_chunks
WHERE project_id = #{projectId}

    AND language = #{language}


    AND chunk_type = #{chunkType}


    AND file_path LIKE #{filePath} || '%'



        AND metadata->>#{entry.key} = #{entry.value}


ORDER BY embedding <=> #{queryVector}::vector
LIMIT #{topK}
